     1→#!/usr/bin/env node
     2→/**
     3→ * End-to-End Testing CLI Tool (T036k)
     4→ *
     5→ * Simple CLI for manual end-to-end testing of classification pipeline.
     6→ * Supports single email, batch, and date-range processing modes.
     7→ *
     8→ * Usage:
     9→ *   npm run test:pipeline -- --mode single --message-id <id>
    10→ *   npm run test:pipeline -- --mode batch --limit 10
    11→ *   npm run test:pipeline -- --mode date-range --start 2025-09-01 --end 2025-09-30 --limit 50
    12→ *   npm run test:pipeline -- --dry-run  # Classify without persisting
    13→ *
    14→ * Output:
    15→ *   - Per-email: [message_id] subject → labels: [label1, label2] (confidence: 0.85) - 8.3s
    16→ *   - Summary: Processed 10 emails in 83.5s (avg 8.35s/email), 9 success, 1 error
    17→ *   - Explainability traces: ./test-pipeline-results/<timestamp>/<message_id>.json
    18→ */
    19→
    20→import { promises as fs } from 'fs';
    21→import { join, dirname } from 'path';
    22→import {
    23→  fetchEmailById,
    24→  fetchUnclassifiedEmails,
    25→  fetchEmailsByDateRange,
    26→  closePool as closeQueryPool,
    27→} from '../persistence/email-query';
    28→import { saveClassificationResult, closePool as closeWriterPool } from '../persistence/classification-writer';
    29→import { ClassificationPipeline } from '../../../classification-engine/src/pipeline/classification-pipeline';
    30→import { ConfigurationLoader } from '../../../classification-engine/src/config/config-loader';
    31→import type {
    32→  ProcessingConfig,
    33→  CategoryConfiguration,
    34→} from '../../../classification-engine/src/types/category-configuration';
    35→import type { EmailMessage } from '../../../classification-engine/src/types/email-message';
    36→import type { ClassificationResult } from '../../../classification-engine/src/types/classification-result';
    37→
    38→/**
    39→ * CLI argument structure
    40→ */
    41→export interface CLIArguments {
    42→  mode: 'single' | 'batch' | 'date-range';
    43→  messageId?: string;
    44→  limit?: number;
    45→  startDate?: string;
    46→  endDate?: string;
    47→  dryRun: boolean;
    48→}
    49→
    50→/**
    51→ * Processing summary statistics
    52→ */
    53→export interface ProcessingSummary {
    54→  totalEmails: number;
    55→  success: number;
    56→  errors: number;
    57→  totalDurationMs: number;
    58→  errorDetails: Array<{ messageId: string; error: string }>;
    59→}
    60→
    61→/**
    62→ * Find the monorepo root directory by searching upward for package.json with workspaces
    63→ *
    64→ * @param startDir - Directory to start searching from (defaults to current working directory)
    65→ * @returns Path to monorepo root directory
    66→ * @throws Error if monorepo root cannot be found
    67→ */
    68→export async function findRepoRoot(startDir: string = process.cwd()): Promise<string> {
    69→  let currentDir = startDir;
    70→  const root = '/';
    71→
    72→  while (currentDir !== root) {
    73→    try {
    74→      const packageJsonPath = join(currentDir, 'package.json');
    75→      const packageJsonContent = await fs.readFile(packageJsonPath, 'utf-8');
    76→      const packageJson = JSON.parse(packageJsonContent);
    77→
    78→      // Check if this package.json has workspaces field (indicates monorepo root)
    79→      if (packageJson.workspaces) {
    80→        return currentDir;
    81→      }
    82→    } catch {
    83→      // package.json not found or not readable, continue searching
    84→    }
    85→
    86→    // Move up one directory
    87→    currentDir = dirname(currentDir);
    88→  }
    89→
    90→  throw new Error('Could not find monorepo root (package.json with workspaces field)');
    91→}
    92→
    93→/**
    94→ * Display help message
    95→ */
    96→function displayHelp(): void {
    97→  console.log(`
    98→End-to-End Classification Pipeline Testing Tool
    99→
   100→Usage:
   101→  npm run test:pipeline -- --mode <mode> [options]
   102→
   103→Modes:
   104→  single       Process a single email by message ID
   105→  batch        Process multiple unclassified emails
   106→  date-range   Process emails within a date range
   107→
   108→Options:
   109→  --mode <mode>           Required: single, batch, or date-range
   110→  --message-id <id>       Required for single mode: Gmail message ID
   111→  --limit <number>        Optional: Maximum emails to process (default: 10 for batch, 100 for date-range)
   112→  --start <YYYY-MM-DD>    Required for date-range: Start date
   113→  --end <YYYY-MM-DD>      Required for date-range: End date
   114→  --dry-run               Optional: Classify without persisting to database
   115→  --help                  Display this help message
   116→
   117→Examples:
   118→  # Single email
   119→  npm run test:pipeline -- --mode single --message-id 18f2a3b4c5d6e7f8
   120→
   121→  # Batch processing
   122→  npm run test:pipeline -- --mode batch --limit 10
   123→
   124→  # Date range
   125→  npm run test:pipeline -- --mode date-range --start 2025-09-01 --end 2025-09-30 --limit 50
   126→
   127→  # Dry run (no database writes)
   128→  npm run test:pipeline -- --mode batch --limit 5 --dry-run
   129→
   130→Output:
   131→  - Per-email results with labels, confidence, and processing time
   132→  - Summary statistics (total, success, errors, average time)
   133→  - Explainability traces in ./test-pipeline-results/<timestamp>/
   134→
   135→Configuration:
   136→  - Config files automatically located in repo root config/
   137→  - Database connection from environment variables
   138→  - Build classification-engine before first run: npm run build --workspace=packages/classification-engine
   139→`);
   140→}
   141→
   142→/**
   143→ * Parse command line arguments
   144→ *
   145→ * @param args - Process arguments (excluding node and script path)
   146→ * @returns Parsed CLI arguments
   147→ * @throws Error if required arguments missing or invalid
   148→ */
   149→export function parseArguments(args: string[]): CLIArguments {
   150→  // Check for help flag first
   151→  if (args.includes('--help') || args.includes('-h')) {
   152→    displayHelp();
   153→    process.exit(0);
   154→  }
   155→
   156→  const result: Partial<CLIArguments> = {
   157→    dryRun: false,
   158→  };
   159→
   160→  for (let i = 0; i < args.length; i++) {
   161→    const arg = args[i];
   162→
   163→    switch (arg) {
   164→    case '--mode':
   165→      if (i + 1 >= args.length) {
   166→        throw new Error('Missing value for --mode argument');
   167→      }
   168→      result.mode = args[++i] as 'single' | 'batch' | 'date-range';
   169→      break;
   170→    case '--message-id':
   171→      if (i + 1 >= args.length) {
   172→        throw new Error('Missing value for --message-id argument');
   173→      }
   174→      result.messageId = args[++i];
   175→      break;
   176→    case '--limit':
   177→      if (i + 1 >= args.length) {
   178→        throw new Error('Missing value for --limit argument');
   179→      }
   180→      result.limit = parseInt(args[++i], 10);
   181→      break;
   182→    case '--start':
   183→      if (i + 1 >= args.length) {
   184→        throw new Error('Missing value for --start argument');
   185→      }
   186→      result.startDate = args[++i];
   187→      break;
   188→    case '--end':
   189→      if (i + 1 >= args.length) {
   190→        throw new Error('Missing value for --end argument');
   191→      }
   192→      result.endDate = args[++i];
   193→      break;
   194→    case '--dry-run':
   195→      result.dryRun = true;
   196→      break;
   197→    }
   198→  }
   199→
   200→  // Validate required arguments
   201→  if (!result.mode) {
   202→    throw new Error('Mode is required (--mode single|batch|date-range)');
   203→  }
   204→
   205→  if (!['single', 'batch', 'date-range'].includes(result.mode)) {
   206→    throw new Error('Invalid mode. Must be: single, batch, or date-range');
   207→  }
   208→
   209→  if (result.mode === 'single' && !result.messageId) {
   210→    throw new Error('message-id is required for single mode (--message-id <id>)');
   211→  }
   212→
   213→  if (result.mode === 'date-range') {
   214→    if (!result.startDate || !result.endDate) {
   215→      throw new Error(
   216→        'Both start and end dates are required for date-range mode (--start YYYY-MM-DD --end YYYY-MM-DD)'
   217→      );
   218→    }
   219→  }
   220→
   221→  return result as CLIArguments;
   222→}
   223→
   224→/**
   225→ * Load configuration from config directory
   226→ *
   227→ * @returns Loaded processing configuration
   228→ * @throws Error if configuration loading fails
   229→ */
   230→async function loadConfiguration(): Promise<ProcessingConfig> {
   231→  // Find monorepo root to locate config directory
   232→  const repoRoot = await findRepoRoot();
   233→
   234→  const configLoader = new ConfigurationLoader({
   235→    configDir: join(repoRoot, 'config'),
   236→    enableHotReload: false,
   237→    validateOnLoad: true,
   238→  });
   239→
   240→  const categoryConfigResult = await configLoader.loadCategoryConfiguration();
   241→
   242→  if (!categoryConfigResult.validationPassed) {
   243→    throw new Error(`Configuration validation failed:\n${categoryConfigResult.validationErrors.join('\n')}`);
   244→  }
   245→
   246→  // Validate config exists before type assertion
   247→  if (!categoryConfigResult.config) {
   248→    throw new Error('Configuration loading returned empty config');
   249→  }
   250→
   251→  // Safely extract processing_config with type assertion
   252→  const config = categoryConfigResult.config as CategoryConfiguration;
   253→  if (!config.processing_config) {
   254→    throw new Error('Missing processing_config in category configuration');
   255→  }
   256→
   257→  return config.processing_config;
   258→}
   259→
   260→/**
   261→ * Process single email through classification pipeline
   262→ *
   263→ * @param messageId - Gmail message ID
   264→ * @param config - Processing configuration
   265→ * @param dryRun - If true, skip persistence
   266→ * @returns Processing summary
   267→ */
   268→export async function processSingleEmail(
   269→  messageId: string,
   270→  config: ProcessingConfig,
   271→  dryRun: boolean
   272→): Promise<ProcessingSummary> {
   273→  const summary: ProcessingSummary = {
   274→    totalEmails: 1,
   275→    success: 0,
   276→    errors: 0,
   277→    totalDurationMs: 0,
   278→    errorDetails: [],
   279→  };
   280→
   281→  const startTime = Date.now();
   282→
   283→  try {
   284→    // 1. Fetch email from database
   285→    console.log(`Fetching email: ${messageId}`);
   286→    const email = await fetchEmailById(messageId);
   287→
   288→    // 2. Initialize pipeline
   289→    const pipeline = new ClassificationPipeline(config);
   290→
   291→    // 3. Classify email
   292→    console.log(`Classifying: [${email.id}] ${email.subject}`);
   293→    const result = await pipeline.classify(email);
   294→
   295→    // 4. Output result
   296→    console.log(formatEmailOutput(email, result));
   297→
   298→    // 5. Persist result (unless dry-run)
   299→    if (!dryRun) {
   300→      await saveClassificationResult(messageId, result);
   301→      console.log(`Persisted classification result for ${messageId}`);
   302→    } else {
   303→      console.log(`[DRY RUN] Skipped persistence for ${messageId}`);
   304→    }
   305→
   306→    // 6. Write explainability trace
   307→    const tracePath = await writeExplainabilityTrace(email, result);
   308→    console.log(`Explainability trace: ${tracePath}`);
   309→
   310→    summary.success = 1;
   311→    summary.totalDurationMs = Date.now() - startTime;
   312→  } catch (error) {
   313→    summary.errors = 1;
   314→    summary.totalDurationMs = Date.now() - startTime;
   315→    summary.errorDetails.push({
   316→      messageId,
   317→      error: error instanceof Error ? error.message : String(error),
   318→    });
   319→
   320→    console.error(`Error processing ${messageId}: ${error instanceof Error ? error.message : String(error)}`);
   321→  }
   322→
   323→  return summary;
   324→}
   325→
   326→/**
   327→ * Process batch of unclassified emails
   328→ *
   329→ * @param limit - Maximum number of emails to process
   330→ * @param config - Processing configuration
   331→ * @param dryRun - If true, skip persistence
   332→ * @returns Processing summary
   333→ */
   334→export async function processBatchEmails(
   335→  limit: number,
   336→  config: ProcessingConfig,
   337→  dryRun: boolean
   338→): Promise<ProcessingSummary> {
   339→  const summary: ProcessingSummary = {
   340→    totalEmails: 0,
   341→    success: 0,
   342→    errors: 0,
   343→    totalDurationMs: 0,
   344→    errorDetails: [],
   345→  };
   346→
   347→  const startTime = Date.now();
   348→
   349→  try {
   350→    // 1. Fetch unclassified emails
   351→    console.log(`Fetching up to ${limit} unclassified emails...`);
   352→    const emails = await fetchUnclassifiedEmails(limit);
   353→
   354→    summary.totalEmails = emails.length;
   355→    console.log(`Found ${emails.length} emails to process\n`);
   356→
   357→    if (emails.length === 0) {
   358→      console.log('No unclassified emails found.');
   359→      summary.totalDurationMs = Date.now() - startTime;
   360→      return summary;
   361→    }
   362→
   363→    // 2. Initialize pipeline
   364→    const pipeline = new ClassificationPipeline(config);
   365→
   366→    // 3. Process each email
   367→    for (const email of emails) {
   368→      try {
   369→        console.log(`Classifying [${email.id}] ${email.subject}`);
   370→        const result = await pipeline.classify(email);
   371→
   372→        console.log(formatEmailOutput(email, result));
   373→
   374→        if (!dryRun) {
   375→          await saveClassificationResult(email.id, result);
   376→        }
   377→
   378→        await writeExplainabilityTrace(email, result);
   379→
   380→        summary.success++;
   381→      } catch (error) {
   382→        summary.errors++;
   383→        summary.errorDetails.push({
   384→          messageId: email.id,
   385→          error: error instanceof Error ? error.message : String(error),
   386→        });
   387→
   388→        console.error(`Error processing ${email.id}: ${error instanceof Error ? error.message : String(error)}`);
   389→      }
   390→    }
   391→
   392→    summary.totalDurationMs = Date.now() - startTime;
   393→  } catch (error) {
   394→    console.error(`Fatal error in batch processing: ${error instanceof Error ? error.message : String(error)}`);
   395→    throw error;
   396→  }
   397→
   398→  return summary;
   399→}
   400→
   401→/**
   402→ * Process emails within date range
   403→ *
   404→ * @param startDate - Start date (YYYY-MM-DD)
   405→ * @param endDate - End date (YYYY-MM-DD)
   406→ * @param limit - Maximum number of emails to process
   407→ * @param config - Processing configuration
   408→ * @param dryRun - If true, skip persistence
   409→ * @returns Processing summary
   410→ */
   411→export async function processDateRangeEmails(
   412→  startDate: string,
   413→  endDate: string,
   414→  limit: number,
   415→  config: ProcessingConfig,
   416→  dryRun: boolean
   417→): Promise<ProcessingSummary> {
   418→  const summary: ProcessingSummary = {
   419→    totalEmails: 0,
   420→    success: 0,
   421→    errors: 0,
   422→    totalDurationMs: 0,
   423→    errorDetails: [],
   424→  };
   425→
   426→  const startTime = Date.now();
   427→
   428→  try {
   429→    // Parse and validate dates
   430→    const start = new Date(startDate);
   431→    const end = new Date(endDate);
   432→
   433→    // Validate dates are valid
   434→    if (isNaN(start.getTime()) || isNaN(end.getTime())) {
   435→      throw new Error('Invalid date format. Use YYYY-MM-DD format for dates');
   436→    }
   437→
   438→    if (start > end) {
   439→      throw new Error('Invalid date range: start date must be before end date');
   440→    }
   441→
   442→    // 1. Fetch emails by date range
   443→    console.log(`Fetching emails from ${startDate} to ${endDate} (limit: ${limit})...`);
   444→    const emails = await fetchEmailsByDateRange(start, end, limit);
   445→
   446→    summary.totalEmails = emails.length;
   447→    console.log(`Found ${emails.length} emails to process\n`);
   448→
   449→    if (emails.length === 0) {
   450→      console.log('No emails found in date range.');
   451→      summary.totalDurationMs = Date.now() - startTime;
   452→      return summary;
   453→    }
   454→
   455→    // 2. Initialize pipeline
   456→    const pipeline = new ClassificationPipeline(config);
   457→
   458→    // 3. Process each email
   459→    for (const email of emails) {
   460→      try {
   461→        console.log(`Classifying [${email.id}] ${email.subject}`);
   462→        const result = await pipeline.classify(email);
   463→
   464→        console.log(formatEmailOutput(email, result));
   465→
   466→        if (!dryRun) {
   467→          await saveClassificationResult(email.id, result);
   468→        }
   469→
   470→        await writeExplainabilityTrace(email, result);
   471→
   472→        summary.success++;
   473→      } catch (error) {
   474→        summary.errors++;
   475→        summary.errorDetails.push({
   476→          messageId: email.id,
   477→          error: error instanceof Error ? error.message : String(error),
   478→        });
   479→
   480→        console.error(`Error processing ${email.id}: ${error instanceof Error ? error.message : String(error)}`);
   481→      }
   482→    }
   483→
   484→    summary.totalDurationMs = Date.now() - startTime;
   485→  } catch (error) {
   486→    console.error(`Fatal error in date range processing: ${error instanceof Error ? error.message : String(error)}`);
   487→    throw error;
   488→  }
   489→
   490→  return summary;
   491→}
   492→
   493→/**
   494→ * Format per-email output line
   495→ *
   496→ * @param email - Email message
   497→ * @param result - Classification result
   498→ * @returns Formatted output string
   499→ */
   500→export function formatEmailOutput(email: EmailMessage, result: ClassificationResult): string {
   501→  const labels = result.selectedLabels.map((label) => label.subtype || label.category).join(', ');
   502→  const primaryLabel = result.selectedLabels.find((l) => l.isPrimary);
   503→  const confidence = primaryLabel ? primaryLabel.confidence.toFixed(2) : '0.00';
   504→  const durationSec = (result.processingDurationMs / 1000).toFixed(1);
   505→
   506→  return `[${email.id}] ${email.subject} → labels: [${labels || 'none'}] (confidence: ${confidence}) - ${durationSec}s`;
   507→}
   508→
   509→/**
   510→ * Format summary statistics
   511→ *
   512→ * @param summary - Processing summary
   513→ * @returns Formatted summary string
   514→ */
   515→export function formatSummary(summary: ProcessingSummary): string {
   516→  const totalSec = (summary.totalDurationMs / 1000).toFixed(1);
   517→  const avgSec = summary.totalEmails > 0 ? (summary.totalDurationMs / 1000 / summary.totalEmails).toFixed(2) : '0.00';
   518→
   519→  let output = `\n${'='.repeat(80)}\n`;
   520→  output += `Processed ${summary.totalEmails} emails in ${totalSec}s (avg ${avgSec}s/email)\n`;
   521→  output += `${summary.success} success, ${summary.errors} errors\n`;
   522→
   523→  if (summary.errorDetails.length > 0) {
   524→    output += '\nErrors:\n';
   525→    for (const error of summary.errorDetails) {
   526→      output += `  - [${error.messageId}] ${error.error}\n`;
   527→    }
   528→  }
   529→
   530→  output += `${'='.repeat(80)}\n`;
   531→
   532→  return output;
   533→}
   534→
   535→/**
   536→ * Write explainability trace to file
   537→ *
   538→ * @param email - Email message
   539→ * @param result - Classification result
   540→ * @returns Path to written trace file
   541→ */
   542→export async function writeExplainabilityTrace(email: EmailMessage, result: ClassificationResult): Promise<string> {
   543→  // Find monorepo root for consistent output location
   544→  const repoRoot = await findRepoRoot();
   545→
   546→  // Create timestamped output directory
   547→  const timestamp = new Date().toISOString().replace(/[:.]/g, '-').split('.')[0].replace('T', '-');
   548→  const outputDir = join(repoRoot, 'test-pipeline-results', timestamp);
   549→
   550→  await fs.mkdir(outputDir, { recursive: true });
   551→
   552→  // Write trace JSON
   553→  const tracePath = join(outputDir, `${email.id}.json`);
   554→  const trace = {
   555→    messageId: email.id,
   556→    subject: email.subject,
   557→    from: email.from.email,
   558→    date: email.date,
   559→    classificationResult: result,
   560→    timestamp: new Date().toISOString(),
   561→  };
   562→
   563→  await fs.writeFile(tracePath, JSON.stringify(trace, null, 2));
   564→
   565→  return tracePath;
   566→}
   567→
   568→/**
   569→ * Main CLI entry point
   570→ *
   571→ * @param args - Command line arguments
   572→ * @returns Exit code (0 = success, 1 = error)
   573→ */
   574→export async function runTestPipeline(args: string[]): Promise<number> {
   575→  try {
   576→    // 1. Parse arguments
   577→    const cliArgs = parseArguments(args);
   578→
   579→    console.log(`\nTest Pipeline - Mode: ${cliArgs.mode}${cliArgs.dryRun ? ' [DRY RUN]' : ''}\n`);
   580→
   581→    // 2. Load configuration
   582→    console.log('Loading configuration...');
   583→    const config = await loadConfiguration();
   584→    console.log('Configuration loaded successfully\n');
   585→
   586→    // 3. Process based on mode
   587→    let summary: ProcessingSummary;
   588→
   589→    switch (cliArgs.mode) {
   590→    case 'single':
   591→      summary = await processSingleEmail(cliArgs.messageId!, config, cliArgs.dryRun);
   592→      break;
   593→
   594→    case 'batch':
   595→      summary = await processBatchEmails(cliArgs.limit || 10, config, cliArgs.dryRun);
   596→      break;
   597→
   598→    case 'date-range':
   599→      summary = await processDateRangeEmails(
   600→          cliArgs.startDate!,
   601→          cliArgs.endDate!,
   602→          cliArgs.limit || 100,
   603→          config,
   604→          cliArgs.dryRun
   605→      );
   606→      break;
   607→    }
   608→
   609→    // 4. Print summary
   610→    console.log(formatSummary(summary));
   611→
   612→    // 5. Cleanup
   613→    await closeQueryPool();
   614→    await closeWriterPool();
   615→
   616→    // 6. Return exit code
   617→    return summary.errors > 0 ? 1 : 0;
   618→  } catch (error) {
   619→    console.error(`\nFatal error: ${error instanceof Error ? error.message : String(error)}`);
   620→
   621→    // Cleanup on error
   622→    try {
   623→      await closeQueryPool();
   624→      await closeWriterPool();
   625→    } catch {
   626→      // Ignore cleanup errors
   627→    }
   628→
   629→    return 1;
   630→  }
   631→}
   632→
   633→/**
   634→ * CLI execution (only when run directly)
   635→ */
   636→if (require.main === module) {
   637→  runTestPipeline(process.argv.slice(2))
   638→    .then((exitCode) => {
   639→      process.exit(exitCode);
   640→    })
   641→    .catch((error) => {
   642→      console.error('Unexpected error:', error);
   643→      process.exit(1);
   644→    });
   645→}
