/**
 * Execute classification pipeline on single email
 *
 * Executes all 9 pipeline stages sequentially with proper context propagation:
 * 1. Hard Assertions
 * 2. Strong Indicators
 * 3. Rule-Based Scoring
 * 4. Attribute Detection
 * 5. Attribute Influence
 * 6. Disambiguation
 * 7. Multi-Label Selection
 * 8. AI Routing (+ Feature Extraction + AI Classification + Final Decision if needed)
 * 9. Audit Trail Generation
 *
 * @param email - Email message to classify
 * @returns Complete classification result with selected labels and explainability trace
 * @throws {Error} If email validation fails or any stage encounters unrecoverable error
 */
async classify(email: EmailMessage): Promise<ClassificationResult> {
  const pipelineStartTime = Date.now();

  try {
    // Validate email input
    validateEmailInput(email);

    // Initialize classification context
    const context: ClassificationContext = {
      emailId: email.id,
      sessionId: `session-${Date.now()}-${email.id}`,
      categoryScores: {},
      hardAssertionsApplied: [],
      strongIndicatorSeeds: {},
      stageTimings: {},
      configurationRefs: {},
    };

    // Stage 1: Hard Assertions
    const hardAssertionsResult = executeHardAssertions(email, context, {
      categorySignals: this.config.category_signals,
      confidenceThresholds: this.config.confidence_thresholds,
    });

    // Stage 2: Strong Indicators
    const strongIndicatorsResult = executeStrongIndicators(email, context, {
      categorySignals: this.config.category_signals,
      confidenceThresholds: this.config.confidence_thresholds,
    });

    // Stage 3: Rule-Based Scoring
    const ruleScoringResult = executeRuleScoring(email, context, {
      topLevelCategories: this.config.top_level_categories,
    });

    // Stage 4: Attribute Detection
    const attributeDetectionResult = executeAttributeDetection(email, context, {
      attributes: this.config.attributes,
    });

    // Stage 5: Attribute Influence
    const attributeInfluenceResult = executeAttributeInfluence(email, context, {
      attributeRelevance: this.config.attribute_relevance,
      attributes: this.config.attributes,
    });

    // Stage 6: Disambiguation
    const disambiguationResult = executeDisambiguation(context, {
      categorySignals: this.config.category_signals,
      settings: this.config.settings,
    });

    // Stage 7: Multi-Label Selection
    const multiLabelResult = executeMultiLabelSelection(context, {
      multiLabelPolicy: this.config.multi_label_policy,
      confidenceThresholds: this.config.confidence_thresholds,
    });

    // Stage 8: AI Routing and Processing
    const aiRoutingResult = executeAIRouting(context, {
      confidenceThresholds: this.config.confidence_thresholds,
      settings: this.config.settings,
    });

    let finalDecisionResult;

    if (aiRoutingResult.requiresAi) {
      // Execute AI Feature Extraction
      const featureExtractionResult = await executeAIFeatureExtraction(email, context, {
        aiPrompts: this.config.ai_prompts,
        featureExtractionSchema: this.config.feature_extraction_schema,
      });

      // Execute AI Classification
      const aiClassificationResult = await executeAIClassification(
        email,
        context,
        featureExtractionResult.extractedFeatures,
        {
          aiPrompts: this.config.ai_prompts,
          topLevelCategories: this.config.top_level_categories,
        }
      );

      // Execute Final Decision with AI results
      finalDecisionResult = executeFinalDecision(context, aiClassificationResult.categoryScores, {
        settings: this.config.settings,
        multiLabelPolicy: this.config.multi_label_policy,
        confidenceThresholds: this.config.confidence_thresholds,
        topLevelCategories: this.config.top_level_categories,
      });
    } else {
