          totalLabels: finalDecisionResult.selectedLabels.length,
          primaryCategory: finalDecisionResult.selectedLabels.find((l) => l.isPrimary)?.category || null,
          confidenceRange: [
            Math.min(...finalDecisionResult.selectedLabels.map((l) => l.confidence)),
            Math.max(...finalDecisionResult.selectedLabels.map((l) => l.confidence)),
          ],
          selectionMethod: aiRoutingResult.requiresAi ? 'ai_classification' : 'rule_based',
          needsAi: aiRoutingResult.requiresAi,
        },
        needsAiClassification: aiRoutingResult.requiresAi,
        processingDurationMs: totalDuration,
        explainabilityTrace: auditTrailResult.explainabilityTrace,
      };
    } catch (error) {
      // Capture error with processing time
      const pipelineEndTime = Date.now();
      throw new Error(
        `Classification pipeline failed for email ${email.id} after ${pipelineEndTime - pipelineStartTime}ms: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Process multiple emails sequentially
   *
   * @param emails - Array of email messages to classify
   * @returns Array of classification results or error results
   */
  async classifyBatch(emails: EmailMessage[]): Promise<Array<ClassificationResult | ClassificationErrorResult>> {
    const results: Array<ClassificationResult | ClassificationErrorResult> = [];

    for (const email of emails) {
      const startTime = Date.now();
      try {
        const result = await this.classify(email);
        results.push(result);
      } catch (error) {
        // Continue processing batch on individual email error
        results.push({
          error: error instanceof Error ? error : new Error(String(error)),
          emailId: email.id,
          processingDurationMs: Date.now() - startTime,
        });
      }
    }

    return results;
  }
}

